'use client';

import { useEffect, useState } from 'react';
import { createClient } from '@/lib/supabase/client';
import { Button } from '@/components/ui/button';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { Badge } from '@/components/ui/badge';
import { Progress } from '@/components/ui/progress';
import { CreditCard, Loader2, ExternalLink } from 'lucide-react';
import { toast } from 'sonner';
import { PLANS } from '@/lib/constants';
import type { Organization } from '@/types';

export default function BillingPage() {
  const [organization, setOrganization] = useState<Organization | null>(null);
  const [loading, setLoading] = useState(true);
  const [upgrading, setUpgrading] = useState(false);
  const supabase = createClient();

  useEffect(() => {
    const loadOrg = async () => {
      const { data: { user } } = await supabase.auth.getUser();
      if (!user) return;

      const { data: profile } = await supabase
        .from('profiles')
        .select('organization_id')
        .eq('id', user.id)
        .single();

      if (profile?.organization_id) {
        const { data: org } = await supabase
          .from('organizations')
          .select('*')
          .eq('id', profile.organization_id)
          .single();
        setOrganization(org as Organization);
      }
      setLoading(false);
    };

    loadOrg();
  }, []);

  const handleUpgrade = async (plan: string) => {
    setUpgrading(true);
    try {
      const res = await fetch('/api/stripe/checkout', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ plan, interval: 'monthly' }),
      });

      const { url, error } = await res.json();
      if (error) throw new Error(error);
      if (url) window.location.href = url;
    } catch {
      toast.error('Failed to start checkout');
    } finally {
      setUpgrading(false);
    }
  };

  const handleManageBilling = async () => {
    try {
      const res = await fetch('/api/stripe/portal', {
        method: 'POST',
      });
      const { url, error } = await res.json();
      if (error) throw new Error(error);
      if (url) window.location.href = url;
    } catch {
      toast.error('Failed to open billing portal');
    }
  };

  if (loading) {
    return (
      <div className="flex items-center justify-center py-16">
        <Loader2 className="h-8 w-8 animate-spin text-muted-foreground" />
      </div>
    );
  }

  const plan = organization?.plan || 'free';
  const planConfig = PLANS[plan];
  const docUsagePercent = organization
    ? (organization.doc_used / organization.doc_quota) * 100
    : 0;
  const surveyUsagePercent = organization
    ? (organization.survey_used / organization.survey_quota) * 100
    : 0;

  return (
    <div className="space-y-6 max-w-3xl">
      <div>
        <h1 className="text-3xl font-bold tracking-tight">Billing</h1>
        <p className="text-muted-foreground">Manage your subscription and usage</p>
      </div>

      {/* Current Plan */}
      <Card>
        <CardHeader>
          <div className="flex items-center justify-between">
            <div>
              <CardTitle className="flex items-center gap-2">
                <CreditCard className="h-5 w-5" />
                Current Plan
              </CardTitle>
              <CardDescription>
                {plan === 'free' ? 'Free plan' : `Billed monthly`}
              </CardDescription>
            </div>
            <Badge variant="default" className="text-lg px-3 py-1">
              {planConfig?.name || 'Free'}
            </Badge>
          </div>
        </CardHeader>
        <CardContent className="space-y-4">
          <div className="flex items-baseline gap-1">
            <span className="text-4xl font-bold">${planConfig?.price || 0}</span>
            {planConfig && planConfig.price > 0 && (
              <span className="text-muted-foreground">/month</span>
            )}
          </div>

          {organization?.stripe_customer_id && (
            <Button variant="outline" onClick={handleManageBilling}>
              <ExternalLink className="mr-2 h-4 w-4" />
              Manage Billing
            </Button>
          )}
        </CardContent>
      </Card>

      {/* Usage */}
      <Card>
        <CardHeader>
          <CardTitle>Usage This Month</CardTitle>
        </CardHeader>
        <CardContent className="space-y-6">
          <div className="space-y-2">
            <div className="flex items-center justify-between text-sm">
              <span>Documents processed</span>
              <span className="font-medium">
                {organization?.doc_used || 0} / {organization?.doc_quota || 10}
              </span>
            </div>
            <Progress value={docUsagePercent} className="h-2" />
          </div>
          <div className="space-y-2">
            <div className="flex items-center justify-between text-sm">
              <span>Surveys created</span>
              <span className="font-medium">
                {organization?.survey_used || 0} / {organization?.survey_quota || 5}
              </span>
            </div>
            <Progress value={surveyUsagePercent} className="h-2" />
          </div>
        </CardContent>
      </Card>

      {/* Upgrade */}
      {plan === 'free' && (
        <Card>
          <CardHeader>
            <CardTitle>Upgrade Your Plan</CardTitle>
            <CardDescription>Get more documents, surveys, and AI analyses</CardDescription>
          </CardHeader>
          <CardContent>
            <div className="grid gap-4 sm:grid-cols-2">
              <Card className="border-primary">
                <CardHeader>
                  <CardTitle className="text-base">Pro</CardTitle>
                  <CardDescription>$29/month</CardDescription>
                </CardHeader>
                <CardContent>
                  <Button
                    className="w-full"
                    onClick={() => handleUpgrade('pro')}
                    disabled={upgrading}
                  >
                    {upgrading && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
                    Upgrade to Pro
                  </Button>
                </CardContent>
              </Card>
              <Card>
                <CardHeader>
                  <CardTitle className="text-base">Enterprise</CardTitle>
                  <CardDescription>$99/month</CardDescription>
                </CardHeader>
                <CardContent>
                  <Button
                    variant="outline"
                    className="w-full"
                    onClick={() => handleUpgrade('enterprise')}
                    disabled={upgrading}
                  >
                    Upgrade to Enterprise
                  </Button>
                </CardContent>
              </Card>
            </div>
          </CardContent>
        </Card>
      )}
    </div>
  );
}


