'use client';

import { useCallback, useState } from 'react';
import { useRouter } from 'next/navigation';
import { createClient } from '@/lib/supabase/client';
import { Button } from '@/components/ui/button';
import { Card } from '@/components/ui/card';
import { Progress } from '@/components/ui/progress';
import { Upload, X, FileText, Loader2 } from 'lucide-react';
import { toast } from 'sonner';
import { cn } from '@/lib/utils';

interface UploadZoneProps {
  organizationId: string;
  onUploadComplete?: () => void;
}

interface UploadFile {
  file: File;
  progress: number;
  status: 'pending' | 'uploading' | 'processing' | 'done' | 'error';
  documentId?: string;
  error?: string;
}

export function UploadZone({ organizationId, onUploadComplete }: UploadZoneProps) {
  const [files, setFiles] = useState<UploadFile[]>([]);
  const [isDragging, setIsDragging] = useState(false);
  const [isUploading, setIsUploading] = useState(false);
  const supabase = createClient();
  const router = useRouter();

  const handleDragOver = useCallback((e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(true);
  }, []);

  const handleDragLeave = useCallback(() => {
    setIsDragging(false);
  }, []);

  const handleDrop = useCallback((e: React.DragEvent) => {
    e.preventDefault();
    setIsDragging(false);
    const droppedFiles = Array.from(e.dataTransfer.files).filter(
      (f) => f.type === 'application/pdf' || f.type.startsWith('image/')
    );
    addFiles(droppedFiles);
  }, []);

  const handleFileSelect = useCallback((e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files) {
      addFiles(Array.from(e.target.files));
    }
  }, []);

  const addFiles = (newFiles: File[]) => {
    const uploadFiles: UploadFile[] = newFiles.map((file) => ({
      file,
      progress: 0,
      status: 'pending',
    }));
    setFiles((prev) => [...prev, ...uploadFiles]);
  };

  const removeFile = (index: number) => {
    setFiles((prev) => prev.filter((_, i) => i !== index));
  };

  const uploadAll = async () => {
    setIsUploading(true);

    for (let i = 0; i < files.length; i++) {
      if (files[i].status !== 'pending') continue;

      // Update status to uploading
      setFiles((prev) =>
        prev.map((f, idx) => (idx === i ? { ...f, status: 'uploading' as const, progress: 10 } : f))
      );

      try {
        const file = files[i].file;
        const fileExt = file.name.split('.').pop();
        const filePath = `${organizationId}/${Date.now()}-${Math.random().toString(36).substring(7)}.${fileExt}`;

        // Upload to Supabase Storage
        setFiles((prev) =>
          prev.map((f, idx) => (idx === i ? { ...f, progress: 30 } : f))
        );

        const { error: uploadError } = await supabase.storage
          .from('documents')
          .upload(filePath, file);

        if (uploadError) throw uploadError;

        setFiles((prev) =>
          prev.map((f, idx) => (idx === i ? { ...f, progress: 60 } : f))
        );

        // Create document record
        const { data: doc, error: dbError } = await supabase
          .from('documents')
          .insert({
            organization_id: organizationId,
            uploaded_by: (await supabase.auth.getUser()).data.user?.id,
            file_name: file.name,
            file_url: filePath,
            file_size: file.size,
            file_type: file.type,
            status: 'pending',
          })
          .select()
          .single();

        if (dbError) throw dbError;

        setFiles((prev) =>
          prev.map((f, idx) =>
            idx === i ? { ...f, progress: 80, status: 'processing' as const, documentId: doc.id } : f
          )
        );

        // Trigger AI processing
        const processResponse = await fetch('/api/documents/process', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ documentId: doc.id }),
        });

        if (!processResponse.ok) {
          const err = await processResponse.json();
          throw new Error(err.error || 'Processing failed');
        }

        setFiles((prev) =>
          prev.map((f, idx) =>
            idx === i ? { ...f, progress: 100, status: 'done' as const } : f
          )
        );
      } catch (error) {
        const message = error instanceof Error ? error.message : 'Upload failed';
        setFiles((prev) =>
          prev.map((f, idx) =>
            idx === i ? { ...f, status: 'error' as const, error: message } : f
          )
        );
        toast.error(`Failed to upload ${files[i].file.name}: ${message}`);
      }
    }

    setIsUploading(false);
    toast.success('Upload complete');
    onUploadComplete?.();
    router.refresh();
  };

  const formatSize = (bytes: number) => {
    if (bytes < 1024) return bytes + ' B';
    if (bytes < 1024 * 1024) return (bytes / 1024).toFixed(1) + ' KB';
    return (bytes / (1024 * 1024)).toFixed(1) + ' MB';
  };

  return (
    <div className="space-y-4">
      <div
        onDragOver={handleDragOver}
        onDragLeave={handleDragLeave}
        onDrop={handleDrop}
        className={cn(
          'relative rounded-lg border-2 border-dashed p-12 text-center transition-colors cursor-pointer',
          isDragging
            ? 'border-primary bg-primary/5'
            : 'border-muted-foreground/25 hover:border-primary/50'
        )}
        onClick={() => document.getElementById('file-input')?.click()}
      >
        <input
          id="file-input"
          type="file"
          multiple
          accept=".pdf,.png,.jpg,.jpeg,.tiff,.webp"
          className="hidden"
          onChange={handleFileSelect}
        />
        <Upload className="mx-auto h-10 w-10 text-muted-foreground mb-4" />
        <p className="text-lg font-medium">Drag files here or click to browse</p>
        <p className="text-sm text-muted-foreground mt-1">
          Supports PDF, PNG, JPG, TIFF, WebP
        </p>
      </div>

      {files.length > 0 && (
        <div className="space-y-3">
          {files.map((uploadFile, index) => (
            <Card key={index} className="p-4">
              <div className="flex items-center gap-3">
                <FileText className="h-8 w-8 text-muted-foreground shrink-0" />
                <div className="flex-1 min-w-0">
                  <p className="text-sm font-medium truncate">{uploadFile.file.name}</p>
                  <p className="text-xs text-muted-foreground">
                    {formatSize(uploadFile.file.size)}
                    {uploadFile.status === 'error' && (
                      <span className="text-destructive ml-2">{uploadFile.error}</span>
                    )}
                    {uploadFile.status === 'done' && (
                      <span className="text-green-600 ml-2">Complete</span>
                    )}
                    {uploadFile.status === 'processing' && (
                      <span className="text-blue-600 ml-2">Processing with AI...</span>
                    )}
                  </p>
                  {(uploadFile.status === 'uploading' || uploadFile.status === 'processing') && (
                    <Progress value={uploadFile.progress} className="h-1.5 mt-2" />
                  )}
                </div>
                {uploadFile.status === 'pending' && (
                  <Button
                    variant="ghost"
                    size="icon"
                    className="shrink-0"
                    onClick={(e) => {
                      e.stopPropagation();
                      removeFile(index);
                    }}
                  >
                    <X className="h-4 w-4" />
                  </Button>
                )}
                {uploadFile.status === 'done' && (
                  <span className="text-green-600 text-sm font-medium">Done</span>
                )}
              </div>
            </Card>
          ))}

          <Button
            onClick={uploadAll}
            disabled={isUploading || files.every((f) => f.status !== 'pending')}
            className="w-full"
          >
            {isUploading ? (
              <>
                <Loader2 className="mr-2 h-4 w-4 animate-spin" />
                Processing...
              </>
            ) : (
              <>
                <Upload className="mr-2 h-4 w-4" />
                Upload & Process All
              </>
            )}
          </Button>
        </div>
      )}
    </div>
  );
}


